464	```ts
465	export function makeColumnMesh(
466	  col: Extract<Element, { kind: 'column' }>,
467	  elevM: number,
468	  paint: ViewportPaintBundle | null,
469	): THREE.Mesh {
470	  const bM = THREE.MathUtils.clamp((col.bMm ?? 300) / 1000, 0.05, 2);
471	  const hM = THREE.MathUtils.clamp((col.hMm ?? 300) / 1000, 0.05, 2);
472	  const baseOff = (col.baseConstraintOffsetMm ?? 0) / 1000;
473	  const topOff = col.topConstraintOffsetMm != null ? col.topConstraintOffsetMm / 1000 : 0;
474	  const heightM = col.heightMm != null ? THREE.MathUtils.clamp(col.heightMm / 1000, 0.25, 40) : 3.0;
475	  const yBase = elevM + baseOff;
476	  const geo = new THREE.BoxGeometry(bM, heightM, hM);
477	  const mat = new THREE.MeshStandardMaterial({
478	    color: categoryColorOr(paint, 'wall'),
479	    roughness: paint?.categories.wall.roughness ?? 0.8,
480	    metalness: paint?.categories.wall.metalness ?? 0,
481	  });
482	  const mesh = new THREE.Mesh(geo, mat);
483	  mesh.position.set(
484	    col.positionMm.xMm / 1000,
485	    yBase + heightM / 2 + topOff,
486	    col.positionMm.yMm / 1000,
487	  );
488	  mesh.rotation.y = THREE.MathUtils.degToRad(col.rotationDeg ?? 0);
489	  addEdges(mesh);
490	  return mesh;
491	}
492	
493	export function makeBeamMesh(
494	  beam: Extract<Element, { kind: 'beam' }>,
495	  elevM: number,
496	  paint: ViewportPaintBundle | null,
497	): THREE.Mesh {
498	  const sx = beam.startMm.xMm / 1000;
499	  const sz = beam.startMm.yMm / 1000;
500	  const ex = beam.endMm.xMm / 1000;
501	  const ez = beam.endMm.yMm / 1000;
502	  const dx = ex - sx;
503	  const dz = ez - sz;
504	  const len = Math.max(0.001, Math.hypot(dx, dz));
505	  const wM = THREE.MathUtils.clamp((beam.widthMm ?? 200) / 1000, 0.05, 1);
506	  const hM = THREE.MathUtils.clamp((beam.heightMm ?? 400) / 1000, 0.05, 1);
507	  const geo = new THREE.BoxGeometry(len, hM, wM);
508	  const mat = new THREE.MeshStandardMaterial({
509	    color: categoryColorOr(paint, 'wall'),
510	    roughness: paint?.categories.wall.roughness ?? 0.8,
511	    metalness: paint?.categories.wall.metalness ?? 0,
512	  });
513	  const mesh = new THREE.Mesh(geo, mat);
514	  mesh.position.set(sx + dx / 2, elevM - hM / 2, sz + dz / 2);
515	  mesh.rotation.y = Math.atan2(dz, dx);
516	  addEdges(mesh);
517	  return mesh;
518	}
519	```
